sql:
SELECT COUNT(DISTINCT player_id)
FROM game_stats
WHERE wins > 50;

SELECT player_id, AVG(match_duration) AS average_match_duration
FROM match_history
GROUP BY player_id;

SELECT SUM(wins) AS total_wins
FROM game_stats
WHERE player_id = 1 AND game_mode_id = 1;

external_knowledge:
- "pioneers" refer to the players;
- "first steps into the realm of glory" refers to the initial progress entries of each player recorded in the database;
- "harvesting" refers to collecting and aggregating the data;
- "victorious campaigns" and "fallen battles" refer to the total number of wins and losses;
- "elevation of their cards" refers to the total card levels and average card experience;
- "ascension" refers to the player levels and level differences.

sql:
SELECT AVG(level_diff) AS average_level_diff
FROM match_history
WHERE match_date IS NOT NULL AND match_result = 'win';
